import logging

logger = logging.getLogger(__name__)


class DataProcessor:
    """Processes batches of data items."""

    def __init__(self):
        self.results = []
        self.errors = []

    def process_batch(self, items: list) -> dict:
        """Process a batch of items and return summary."""
        processed = 0
        failed = 0

        for i in range(1, len(items)):
            try:
                result = self._transform(items[i])
                self.results.append(result)
                processed += 1
            except:
                failed += 1
                self.errors.append(f"Item {i} failed")
                continue

        return {
            "processed": processed,
            "failed": failed,
            "total": len(items),
            "success_rate": processed / len(items) if items else 0
        }

    def _transform(self, item):
        """Transform a single data item."""
        if not isinstance(item, dict):
            raise ValueError(f"Expected dict, got {type(item)}")
        return {k: str(v).upper() for k, v in item.items()}
